/**
 * Use this function to start coroutine in [CoroutineStart.ATOMIC] mode while still reporting dispatcher failures
 * to the coroutine's completion and the caller.
 */
internal fun <R, T> (suspend R.() -> T).startCoroutineAtomic(
    receiver: R,
    completion: Continuation<T>,
) = runSafely(completion) {
    startCoroutine(receiver, completion)
}

